 1	import { DetailsItem } from "copiedFromConsole/utils/details-item";
 2	import { NodeHealthCheck } from "data/types";
 3	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 4	
 5	import * as React from "react";
 6	import NodeHealthCheckStatus from "../NodeHealthCheckStatus";
 7	import { DescriptionList } from "@patternfly/react-core";
 8	import { RemediationTemplateLink } from "../../shared/RemediationTemplateLink";
 9	
10	export const DetailsRightPane: React.FC<{
11	  nodeHealthCheck: NodeHealthCheck;
12	}> = ({ nodeHealthCheck }) => {
13	  const { t } = useNodeHealthCheckTranslation();
14	  return (
15	    <DescriptionList aria-label={t("NodeHealthCheck summary")}>
16	      <DetailsItem label={t("Remediator")} obj={nodeHealthCheck}>
17	        <RemediationTemplateLink nodeHealthCheck={nodeHealthCheck} />
18	      </DetailsItem>
19	      {nodeHealthCheck.spec?.maxUnhealthy !== undefined ? (
20	        <DetailsItem
21	          label={t("Max unhealthy")}
22	          obj={nodeHealthCheck}
23	          path="spec.maxUnhealthy"
24	        />
25	      ) : (
26	        <DetailsItem
27	          label={t("Min healthy")}
28	          obj={nodeHealthCheck}
29	          path="spec.minHealthy"
30	        />
31	      )}
32	
33	      <DetailsItem label={t("Observed nodes")} obj={nodeHealthCheck}>
34	        {nodeHealthCheck.status?.observedNodes}
35	      </DetailsItem>
36	
37	      <DetailsItem label={t("Healthy nodes")} obj={nodeHealthCheck}>
38	        {nodeHealthCheck.status?.healthyNodes}
39	      </DetailsItem>
40	
41	      <DetailsItem label={t("Status")} obj={nodeHealthCheck}>
42	        <NodeHealthCheckStatus
43	          nodeHealthCheck={nodeHealthCheck}
44	          withPopover={true}
45	        />
46	      </DetailsItem>
47	    </DescriptionList>
48	  );
49	};

